INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-6e11b43e-moex-00479', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '依最高行政法院裁判見解，關於行政罰法中法律變更時之適用原則之敘述，下列何者錯誤？', '["行政罰法規定行為後法律有變更者，適用行政機關最初裁處時之法律，為從新原則之具體化", "行為後法律雖有變更，如裁處前之法律係有利於受處罰者，適用最有利於受處罰者之規定", "行政機關依法律授權所為之公告，因會對外發生規範效力，故其內容之變更亦屬法律變更", "行政機關為行使裁量權所訂頒之裁量基準，因非屬法律，故其變更即非屬法律變更之情形"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00480', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '甲向主管機關申領身心障礙給付後，檢察官以詐欺取財罪對甲作成緩起訴處分。主管機關乃依法就其 詐領給付之行為，處以給付額兩倍之罰鍰。其裁處權時效應如何起算？', '["自主管機關知悉甲違法時起算", "自甲持不實資料向主管機關提出申請時起算", "自甲受領身心障礙給付時起算", "自檢察官緩起訴處分確定時起算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00481', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '下列何者屬於行政罰法之規制範圍？', '["證券交易法第 59 條第 1 項規定：「證券商自受領證券業務特許證照，或其分支機構經許可並登記 後，於三個月內未開始營業，或雖已開業而自行停止營業連續三個月以上時，主管機關得撤銷其特 許或許可。」", "稅捐稽徵法第24條第1項前段規定：「納稅義務人欠繳應納稅捐者，稅捐稽徵機關得就納稅義務人 相當於應繳稅捐數額之財產，通知有關機關，不得為移轉或設定他項權利。」", "所得稅法第43條之2第1項規定：「自一百年度起，營利事業對關係人之負債占業主權益超過一定 比率者，超過部分之利息支出不得列為費用或損失。」", "道路交通管理處罰條例第12條第1項規定：「汽車有下列情形之一者，處汽車所有人新臺幣三千六 百元以上一萬零八百元以下罰鍰，......。」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00482', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '甲因積欠交通違規罰單新臺幣18,000元，主管機關經催討後仍未繳納，移送行政執行。依行政執行法 規定，執行機關之下列執行行為何者違法？', '["於星期一上午8時對於甲之動產進行查封", "於履行期間屆滿後3年通知甲報告其財產狀況，之後逾3年始進行查封", "命甲報告財產狀況而甲不為報告，認應強制其到場而聲請法院裁定拘提", "於查明甲之經濟狀況後，認為其無法一次完納，經主管機關同意准其分期繳納"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00483', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於行政執行法上之管收，下列敘述何者正確？', '["義務人不繳納怠金及代履行費用，並無適用管收相關規定之可能", "涉及義務人人身自由之限制，行政執行官應自拘提時起24小時內作成管收處分", "義務人如不服管收之決定，得準用民事訴訟法相關規定提出救濟，但管收之執行並不停止", "管收期限最長為3個月，義務人經管收期滿後，所負之公法上金錢給付義務視為已履行而消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00484', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '消防隊為救火破壞門窗直接進入甲之住宅實施灌救。甲依法請求補償門窗損害新臺幣（下同）5萬元， 但主管機關僅核給1萬元，就此差額，甲應如何救濟？', '["向主管機關協議請求國家賠償", "逕向行政法院提起一般給付之訴", "提起訴願請求差額賠償", "循序提起課予義務訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00485', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '下列何者非屬行政程序法所稱之行政程序？', '["考試院修正專門職業及技術人員考試總成績計算規則", "公路監理機關與汽車修理廠締結汽車委託檢驗契約", "警察機關於轄區內進行巡邏", "建築主管機關處理人民對拆除違建疏失提出之舉發"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00486', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '依行政程序法規定，聽證程序自何時開始，於何時終結？', '["當事人提出聽證申請開始；行政機關就該事件作成決定即屬終結", "以主持人就事實或法律問題詢問當事人或其他到場人開始；待所有問答均結束後即終結", "從聽證主持人說明案由開始；待當事人充分陳述意見，事件已達可為決定之程度者，即應終結", "上級機關核准進行聽證開始；將聽證紀錄呈報上級機關時終結"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00487', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '行政程序法中有關閱覽卷宗之規定，下列何者正確？', '["任何人均得請求閱覽、抄錄行政程序有關卷宗資料", "當事人得就未給予閱覽卷宗之處置，直接提起訴願", "閱覽卷宗時如發現其中資料關於他人之記載有錯誤，得請求更正", "適用分離原則，故涉及公務機密之文書資料中，如無保密必要之部分，仍應准許閱覽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00488', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '訴願文書之寄存送達，應依何法律行之，送達生效時點為何？', '["適用訴願法規定，自寄存時發生效力", "依訴願法準用行政程序法，自寄存時發生效力", "依訴願法準用行政訴訟法，自寄存日起經10日發生效力", "依訴願法準用民事訴訟法，自寄存日起經10日發生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL)
